-- Primeiro, buscar todos os corretores ativos (recém criados)
SELECT id, name, email FROM users WHERE role = 'corretor' ORDER BY id;

-- Contar leads órfãos que precisam ser redistribuídos
SELECT COUNT(*) as total_orfaos
FROM leads 
WHERE status = 'em_atendimento' 
  AND corretorId NOT IN (
    SELECT id FROM users WHERE role = 'corretor'
  );

